import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"Tools","description":"","frontmatter":{},"headers":[],"relativePath":"tools.md","filePath":"tools.md"}'),o={name:"tools.md"};function i(r,e,l,c,d,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h1><p>The Tools screen provides access to utilities that support the SWAO workspace rather than running assessments directly. These are configuration, licensing, and diagnostic functions you use to keep the workspace current and troubleshoot issues.</p><p>Access from the TUI main menu by pressing <strong>9</strong>.</p><hr><h2 id="available-tools" tabindex="-1">Available tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available tools&quot;">​</a></h2><h3 id="lenses" tabindex="-1">Lenses <a class="header-anchor" href="#lenses" aria-label="Permalink to &quot;Lenses&quot;">​</a></h3><p>Lenses are reusable viewpoints that filter the signal and compliance view to a specific angle: regulatory, architectural, or persona-based.</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Lens</th><th>What it filters</th></tr></thead><tbody><tr><td>GDPR / DPO</td><td>Data-residency and data-handling controls only</td></tr><tr><td>Financial Services</td><td>DORA, MAS TRM, and SOX-relevant controls</td></tr><tr><td>Security Architect</td><td>All security-related signals across all passes</td></tr><tr><td>Migration Lead</td><td>7R migration signals and landing zone signals only</td></tr></tbody></table><p>Apply a lens from the Tools screen to change which signals appear in the publication and the auditor report without rerunning the assessment. Lenses do not change the underlying signal set -- they change the view.</p><hr><h3 id="licence" tabindex="-1">Licence <a class="header-anchor" href="#licence" aria-label="Permalink to &quot;Licence&quot;">​</a></h3><p>The Licence tool shows:</p><ul><li>Current edition (Community / Consultant / Enterprise)</li><li>Licence key status and expiry</li><li>Features enabled by the current licence</li></ul><p>To activate or update a licence key:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao tools license --key &lt;your-key&gt;</span></span></code></pre></div><p>If you are running Community edition and need to trial Enterprise features, contact your Accenture engagement sponsor or raise a request via the SWAO service catalogue.</p><hr><h3 id="credentials" tabindex="-1">Credentials <a class="header-anchor" href="#credentials" aria-label="Permalink to &quot;Credentials&quot;">​</a></h3><p>Credentials manages the secrets SWAO uses to call external services:</p><table tabindex="0"><thead><tr><th>Credential</th><th>Used for</th></tr></thead><tbody><tr><td>LLM provider API key</td><td>Application and LLM assessment passes</td></tr><tr><td>VCS token</td><td>Cloning private repositories for assessment</td></tr><tr><td>Container registry token</td><td>Pulling images for container pass analysis</td></tr><tr><td>CMDB / ServiceNow token</td><td>Context ingestion from ITSM sources</td></tr></tbody></table><p>Credentials are stored encrypted in the workspace secrets store (<code>wsp/.secrets/</code>), never in <code>.swao.yml</code> or any tracked file. The health check confirms each credential is present and the target service responds before you start an assessment.</p><p>To set a credential:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao tools credentials --set llm-api-key</span></span></code></pre></div><p>SWAO prompts for the value interactively so it does not appear in shell history.</p><hr><h3 id="help" tabindex="-1">Help <a class="header-anchor" href="#help" aria-label="Permalink to &quot;Help&quot;">​</a></h3><p>Opens the in-context help for any SWAO command or screen. You can also access help directly from the command line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao help</span></span>
<span class="line"><span>swao help assess</span></span>
<span class="line"><span>swao help publish</span></span></code></pre></div><p>For the full product documentation, open <code>http://localhost:5173</code> if you are running the SWAO documentation site locally, or visit the project documentation portal.</p>`,30)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
